import React, { useState, useEffect } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const NAV_ITEMS = [
  { to: '/dashboard', label: 'Dashboard', icon: '◉', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
  { to: '/libraries', label: 'Libraries', icon: '⊞', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
  { to: '/books', label: 'Books', icon: '◫', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
  { to: '/requests', label: 'Requests', icon: '◎', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
];

function isMobileDevice() {
  // Detect touch device OR narrow screen — covers Android desktop-site mode too
  return (
    'ontouchstart' in window ||
    navigator.maxTouchPoints > 0 ||
    window.innerWidth <= 1024
  );
}

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const check = () => setIsMobile(isMobileDevice());
    check(); // run on mount
    window.addEventListener('resize', check);
    return () => window.removeEventListener('resize', check);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const visibleNav = NAV_ITEMS.filter((n) => n.roles.includes(user?.role));
  const closeSidebar = () => setSidebarOpen(false);

  return (
    <div className="app-shell">

      {/* ── Mobile top bar (JS-controlled) ── */}
      {isMobile && (
        <div className="mobile-topbar">
          <button className="hamburger" onClick={() => setSidebarOpen(true)}>
            ☰
          </button>
          <span className="mobile-logo">Ba Boook Corner</span>
          <span className="mobile-role">{user?.role}</span>
        </div>
      )}

      {/* ── Sidebar overlay ── */}
      {isMobile && sidebarOpen && (
        <div
          className="sidebar-overlay"
          onClick={closeSidebar}
          style={{ display: 'block' }}
        />
      )}

      {/* ── Sidebar ── */}
      <aside
        className="sidebar"
        style={isMobile ? {
          transform: sidebarOpen ? 'translateX(0)' : 'translateX(-100%)',
        } : {
          transform: 'translateX(0)',
        }}
      >
        <div className="sidebar-logo" style={{ position: 'relative' }}>
          <h1>Ba Boook Corner</h1>
          <span>Ba Foundation</span>
          {isMobile && (
            <button className="sidebar-close" onClick={closeSidebar} style={{ display: 'block' }}>
              ✕
            </button>
          )}
        </div>
        <nav className="sidebar-nav">
          {visibleNav.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              className={({ isActive }) => (isActive ? 'active' : '')}
              onClick={closeSidebar}
            >
              <span>{item.icon}</span>
              {item.label}
            </NavLink>
          ))}
        </nav>
        <div className="sidebar-user">
          <div className="name">{user?.full_name}</div>
          <div className="role">{user?.role}</div>
          <button
            className="nav-btn"
            onClick={handleLogout}
            style={{ marginTop: 10, padding: '6px 0', color: 'rgba(250,247,242,0.5)' }}
          >
            ⎋ Sign out
          </button>
        </div>
      </aside>

      {/* ── Main content ── */}
      <main
        className="main-content"
        style={isMobile ? {
          marginLeft: 0,
          paddingTop: '56px',
          paddingBottom: '64px',
        } : {
          marginLeft: '240px',
        }}
      >
        <Outlet />
      </main>

      {/* ── Mobile bottom nav (JS-controlled) ── */}
      {isMobile && (
        <nav className="bottom-nav" style={{ display: 'flex' }}>
          {visibleNav.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              className={({ isActive }) => `bottom-nav-item ${isActive ? 'active' : ''}`}
            >
              <span className="bottom-nav-icon">{item.icon}</span>
              <span className="bottom-nav-label">{item.label}</span>
            </NavLink>
          ))}
          <button className="bottom-nav-item" onClick={handleLogout}>
            <span className="bottom-nav-icon">⎋</span>
            <span className="bottom-nav-label">Logout</span>
          </button>
        </nav>
      )}

    </div>
  );
}
